export type Cell = [number, number];

function isNeighbor([ax, ay]: Cell, [bx, by]: Cell): boolean {
  const dx = Math.abs(ax - bx);
  const dy = Math.abs(ay - by);
  return dx <= 1 && dy <= 1 && (dx !== 0 || dy !== 0);
}

function countLiveNeighbors(cell: Cell, liveCells: Cell[]): number {
  return liveCells.filter((other) => isNeighbor(cell, other)).length;
}

function keyOf([x, y]: Cell): string {
  return `${x},${y}`;
}

function candidateCells(liveCells: Cell[]): Cell[] {
  const seen = new Map<string, Cell>();
  const offsets = [-1, 0, 1];
  for (const [x, y] of liveCells) {
    for (const dx of offsets) {
      for (const dy of offsets) {
        const cell: Cell = [x + dx, y + dy];
        seen.set(keyOf(cell), cell);
      }
    }
  }
  return [...seen.values()];
}

function isAlive(cell: Cell, liveCells: Cell[]): boolean {
  return liveCells.some(([x, y]) => x === cell[0] && y === cell[1]);
}

function livesNextGeneration(cell: Cell, liveCells: Cell[]): boolean {
  const n = countLiveNeighbors(cell, liveCells);
  return n === 3 || (n === 2 && isAlive(cell, liveCells));
}

export function nextGeneration(liveCells: Cell[]): Cell[] {
  return candidateCells(liveCells).filter((cell) =>
    livesNextGeneration(cell, liveCells),
  );
}
